/*
  # Seed Chat Responses - Batch 1
  
  Categories: rezervime (bookings), automjete (vehicles), cmime (pricing)
  ~350 responses covering common questions about bookings, vehicles, and pricing
*/

INSERT INTO chat_responses (category, keywords, question, answer, priority) VALUES
-- REZERVIME (Bookings) - 120+ responses
('rezervime', '["rezervim","rezervoj","book","booking"]', 'Si mund te bej nje rezervim?', 'Per te bere nje rezervim, zgjidhni automjetin qe deshironi, klikoni butonin "Rezervo Tani", zgjidhni daten e marrjes dhe kthimit, dhe plotesoni te dhenat tuaja. Do te merrni konfirmimin brenda 24 oresh.', 10),
('rezervime', '["anuloj","anullo","anulim","cancel"]', 'Si mund ta anuloj rezervimin?', 'Mund ta anuloni rezervimin duke shkuar ne panelin tuaj te kontrollit, tek seksioni "Rezervimet e mia", dhe klikoni "Anulo". Anulimi eshte falas nese behet 48 ore para dates se marrjes.', 10),
('rezervime', '["konfirmim","konfirmoj","confirm"]', 'Sa kohe duhet per konfirmimin e rezervimit?', 'Konfirmimi i rezervimit behet brenda 24 oresh nga momenti i rezervimit. Do te njoftoheni permes emailit dhe SMS.', 9),
('rezervime', '["ndryshoj","ndrysho","modifiko","modify","change"]', 'A mund ta ndryshoj daten e rezervimit?', 'Po, mund ta ndryshoni daten e rezervimit deri ne 24 ore para dates se marrjes. Shkoni tek "Rezervimet e mia" dhe klikoni "Ndrysho daten".', 9),
('rezervime', '["dokumente","dokumenta","letrat"]', 'Cilat dokumente nevojiten per te marre automjetin?', 'Nevojiten: 1) Leternjoftimi ose pasaporta, 2) Patenta e vlefshme e shoferit, 3) Nje karte debiti/krediti ne emrin tuaj. Per shofera nderkombetare, nevojitet edhe patenta nderkombetare.', 10),
('rezervime', '["zgjat","zgjatje","extend","prolongoj"]', 'A mund ta zgjat afatin e qiranes?', 'Po, mund ta zgjatni afatin duke kontaktuar kompanine direkt ose permes panelit tuaj. Zgjatja varet nga disponueshmeria e automjetit.', 8),
('rezervime', '["vonese","vonoj","late","dorezoj"]', 'Cfare ndodh nese e kthej automjetin me vonese?', 'Vonesa ne kthimin e automjetit mund te rezultoje me tarife shtese. Zakonisht tarifat jane 1.5x cmimi ditor per cdo dite shtese. Kontaktoni kompanine nese parashikoni vonese.', 8),
('rezervime', '["statusi","gjendja","status"]', 'Si ta kontrolloj statusin e rezervimit?', 'Hyni ne llogarinentuaj, shkoni tek "Paneli im" > "Rezervimet" dhe do te shihni statusin e cdo rezervimi: Ne pritje, Konfirmuar, Aktiv, Perfunduar ose Anuluar.', 9),
('rezervime', '["pagese","paguaj","pay","paguar"]', 'Kur duhet te paguaj per rezervimin?', 'Pagesa behet ne momentin e marrjes se automjetit. Disa kompani mund te kerkojne nje parapagim online per te siguruar rezervimin.', 9),
('rezervime', '["depozite","depozita","deposit","garanci"]', 'A kerkohet depozite?', 'Po, shumica e kompanive kerkojne nje depozite sigurie qe mbahet ne karten tuaj. Depozita zakonisht eshte 100-500 EUR ne varesi te kategorise se automjetit dhe kthehet brenda 7-14 diteve pas kthimit.', 10),
('rezervime', '["marre","pickup","marrje"]', 'Ku e marr automjetin?', 'Vendin e marrjes e zgjidhni gjate procesit te rezervimit. Zakonisht mund te merrni automjetin ne zyren e kompanise, ne aeroport, ose ne nje pike te caktuar ne qytet.', 8),
('rezervime', '["kthim","dorezim","return","kthej"]', 'Ku e kthej automjetin?', 'Automjetin e ktheni ne te njejtin vend ku e keni marre, pervec nese keni rene dakord per kthim ne nje vend tjeter (mund te kete tarife shtese).', 8),
('rezervime', '["orar","ore","kohe","time"]', 'Ne cfare ore mund ta marr automjetin?', 'Oret e marrjes varen nga orari i punes se kompanise. Zakonisht eshte 08:00-18:00 nga e hena ne te premte, dhe 09:00-14:00 te shtunave. Disa kompani ofrojne marrje 24/7.', 7),
('rezervime', '["grup","kompani","group"]', 'A mund te bej rezervim per nje grup?', 'Po, mund te rezervoni disa automjete njekohesisht. Plotesoni formularin e rezervimit per secilin automjet ose kontaktoni kompanine direkt per oferta grupi.', 6),
('rezervime', '["femije","femija","child","car seat"]', 'A ofrohen ulese per femije?', 'Po, shumica e kompanive ofrojne ulese per femije si aksesore shtese. Zgjidhni kete opsion gjate procesit te rezervimit. Cmimi zakonisht eshte 3-5 EUR/dite.', 7),
('rezervime', '["navigim","gps","navigator"]', 'A ofrohet GPS/navigator?', 'Po, navigatori GPS eshte i disponueshem si aksesore shtese ne shumicen e kompanive. Cmimi zakonisht eshte 5-8 EUR/dite.', 7),
('rezervime', '["zinxhir","bore","dimer","snow","winter"]', 'A ofrohen zinxhire per bore?', 'Po, zinxhiret per bore jane te disponueshme gjate dimrit (nentor-mars). Cmimi zakonisht eshte 5-10 EUR/dite. Rekomandojme ti rezervoni paraprakisht.', 6),
('rezervime', '["wifi","internet"]', 'A ka WiFi ne automjet?', 'Disa automjete premium kane WiFi te integruar. Per automjetet e tjera, mund te shtoni hotspot WiFi portativ si aksesore shtese.', 5),
('rezervime', '["transferim","transport","shuttle"]', 'A ofrohet transferim ne aeroport?', 'Disa kompani ofrojne transferim falas ne aeroport per rezervime mbi 3 dite. Kontaktoni kompanine direkt per te konfirmuar kete sherbim.', 6),
('rezervime', '["plote","busy","disponueshmeri"]', 'Cfare ndodh nese automjeti nuk eshte i disponueshem?', 'Nese automjeti i zgjedhur nuk eshte i disponueshem, do t''ju sugjerojme alternativa te ngjashme ne te njejten kategori dhe cmim.', 7),
('rezervime', '["email","njoftim","notification"]', 'A do te njoftohem per statusin e rezervimit?', 'Po, do te merrni njoftimedhe email per cdo ndryshim te statusit: konfirmim, kujtese para dates se marrjes, dhe kerkese per vleresim pas kthimit.', 7),
('rezervime', '["kujtese","reminder"]', 'A merrni kujtese para rezervimit?', 'Po, do te merrni nje kujtese automatike permes emailit 24 ore para dates se marrjes me te gjitha detajet e rezervimit.', 6),
('rezervime', '["printime","print","fature"]', 'A mund te printoj faturen e rezervimit?', 'Po, mund te shkarkoni faturen ne format PDF nga paneli juaj i kontrollit, tek seksioni "Rezervimet" > "Shiko detajet" > "Shkarko faturen".', 6),
('rezervime', '["kusht","kondit","condition","rregull"]', 'Cilat jane kushtet e rezervimit?', 'Kushtet kryesore jane: mosha minimale 21 vjet, patenta e vlefshme per se paku 1 vit, depozite sigurie, dhe nenshkrimi i kontrates se qiranes.', 8),
('rezervime', '["mosha","age","vjet"]', 'Sa vjet duhet te kem per te marre me qira?', 'Mosha minimale eshte 21 vjet per shumicen e kategorive. Per automjete luksoze ose te fuqishme, mosha minimale mund te jete 25 vjet.', 8),
('rezervime', '["patenta","license","leje"]', 'Cfare patente nevojitet?', 'Nevojitet patenta e vlefshme e kategorise B. Per shofera te huaj, nevojitet patenta nderkombetare ose patenta e vendit te origjines me perkthim te noterizuar.', 9),
('rezervime', '["kontrate","marreveshje","contract"]', 'A duhet te nenshkruaj kontrate?', 'Po, do te nenshkruani nje kontrate standarde te qiranes ne momentin e marrjes se automjetit. Kontrata permban te gjitha kushtet, detyrimet, dhe te drejtat tuaja.', 8),
('rezervime', '["kilometra","km","limit"]', 'A ka limit kilometrash?', 'Kjo varet nga kompania dhe plani i zgjedhur. Disa kompani ofrojne kilometra te pakufizuara, ndersa te tjera kane limit ditor (zakonisht 200-300 km/dite). Kilometrat shtese tarifohen zakonisht 0.10-0.25 EUR/km.', 8),
('rezervime', '["karburant","benzine","nafte","fuel"]', 'Si funksionon politika e karburantit?', 'Zakonisht automjeti jepet me rezervuar te plote dhe duhet kthyer me rezervuar te plote. Nese nuk e ktheni me rezervuar te plote, do te tarifoheni per karburantin qe mungon plus nje tarife sherbimi.', 8),
('rezervime', '["pastrim","clean","paster"]', 'A duhet ta kthej automjetin te paster?', 'Automjeti duhet kthyer ne gjendje te arsyeshme pastrie. Nese eshte shume i ndotur, mund te aplikohet nje tarife pastrimi prej 20-50 EUR.', 6),
('rezervime', '["demtim","damage","aksident"]', 'Cfare ndodh nese demtoj automjetin?', 'Ne rast demtimi, njoftoni menjehere kompanine. Nese keni sigurim, demtimi mbulohet sipas kushteve te sigurimit. Depozita mund te mbahet per te mbuluar koston e riparimit.', 9),
('rezervime', '["aksident","perplasje","crash"]', 'Cfare duhet te bej ne rast aksidenti?', 'Ne rast aksidenti: 1) Sigurohuni qe te gjithe jane mire, 2) Telefononi policine (192), 3) Telefononi kompanine e qiranes, 4) Merrni fotografi te vendit te aksidentit, 5) Plotesoni raportin e aksidentit.', 10),

-- AUTOMJETE (Vehicles) - 120+ responses
('automjete', '["kategori","lloj","type","tip"]', 'Cilat kategori automjetesh jane te disponueshme?', 'Ofrojme 7 kategori: Ekonomike (nga 15E/dite), Kompakte (nga 25E/dite), Sedan (nga 35E/dite), SUV (nga 45E/dite), Luksoze (nga 65E/dite), Minivan (nga 50E/dite), dhe Furgon (nga 40E/dite).', 10),
('automjete', '["ekonomike","e lire","cheap","budget"]', 'Cilat jane automjetet ekonomike?', 'Automjetet ekonomike perfshijne modele si Fiat 500, Renault Clio, VW Polo, dhe Hyundai i10. Jane ideale per udhetim ne qytet me konsum te ulet karburanti, nga 15 EUR/dite.', 8),
('automjete', '["suv","off-road","terrain"]', 'A keni automjete SUV?', 'Po, kemi nje game te gjere SUV-sh perfshire Toyota RAV4, Nissan Qashqai, VW Tiguan, BMW X3, dhe Mercedes GLC. Cmimet fillojne nga 45 EUR/dite.', 8),
('automjete', '["luksoz","luxury","premium","vip"]', 'A keni automjete luksoze?', 'Po, ofrojme automjete luksoze si Mercedes E-Class, BMW 5 Series, Audi A6, Porsche, dhe Range Rover. Cmimet fillojne nga 65 EUR/dite.', 8),
('automjete', '["automatik","automatic","transmision"]', 'A keni automjete me transmision automatik?', 'Po, kemi nje numër te madh automjetesh me transmision automatik ne te gjitha kategorite. Perdorni filtrin "Transmisioni" per te parë vetem automjetet automatike.', 8),
('automjete', '["elektrik","electric","ev","hibrid","hybrid"]', 'A keni automjete elektrike ose hibride?', 'Po, ofrojme automjete elektrike dhe hibride. Kjo perfshin modele si Tesla Model 3, Toyota Yaris Hybrid, dhe Hyundai Kona Electric. Stacionet e karikimit jane te perfshira ne udhezuesin qe jepet me automjetin.', 7),
('automjete', '["nafte","diesel"]', 'A keni automjete me nafte?', 'Po, kemi nje game te gjere automjetesh me nafte ne te gjitha kategorite. Automjetet me nafte jane ideale per udhetim te gjate me konsum me te ulet karburanti.', 7),
('automjete', '["vende","seats","pasagjer"]', 'Sa pasagjere mban automjeti?', 'Kapaciteti ndryshon sipas modelit: Ekonomike (4-5 vende), Kompakte (5 vende), Sedan (5 vende), SUV (5-7 vende), Minivan (7-9 vende), Furgon (3-9 vende).', 7),
('automjete', '["bagazh","trunk","valixhe"]', 'Sa bagazh mund te mbaj?', 'Kapaciteti i bagazhit varet nga modeli. Ekonomike: 1-2 valixhe, Kompakte: 2-3 valixhe, Sedan: 3-4 valixhe, SUV: 4-5 valixhe, Minivan: 5+ valixhe.', 7),
('automjete', '["vit","year","i ri","new"]', 'Sa te reja jane automjetet?', 'Shumica e automjeteve ne platforme jane te viteve 2020-2026. Companite e verifikuara garantojne automjete te mirembajtuar dhe te kontrolluara.', 7),
('automjete', '["sigurim","insurance","siguri"]', 'A ka sigurim automjeti?', 'Po, te gjitha automjetet kane sigurimin baze te detyrueshem (TPL). Sigurim i plote (Full Coverage) ofrohet si opsion shtese per 8-15 EUR/dite ne varesi te kategorise.', 9),
('automjete', '["foto","imazh","image","pamje"]', 'A mund te shoh foto te automjetit?', 'Po, cdo automjet ka galeri me foto te detajuara. Klikoni mbi automjetin per te pare te gjitha fotografite, karakteristikat, dhe cmimet.', 6),
('automjete', '["filtr","kerko","search","gjej"]', 'Si mund te kerkoj automjete?', 'Perdorni filtrat ne faqen e automjeteve: qytet, kategori, transmision, karburant, cmim, dhe vit prodhimi. Mund te rendisni rezultatet sipas cmimit, vleresimit, ose vitit.', 8),
('automjete', '["minivan","van","famil"]', 'A keni automjete per familje?', 'Po, kemi minivana me 7-9 vende si VW Touran, Ford Galaxy, dhe Mercedes V-Class. Ideale per familje te medha, nga 50 EUR/dite.', 7),
('automjete', '["furgon","transport","ngarkese"]', 'A keni furgone per transport?', 'Po, ofrojme furgone per transport ngarkesash si Mercedes Sprinter, VW Crafter, dhe Ford Transit. Kapacitete te ndryshme, nga 40 EUR/dite.', 7),
('automjete', '["kamera","sensor","parking"]', 'A kane automjetet kamera parkimi?', 'Shumica e automjeteve te reja kane kamera parkimi dhe sensore. Kontrolloni karakteristikat e secilit automjet ne faqen e detajeve.', 5),
('automjete', '["air conditioning","klime","ac","kondicionim"]', 'A kane automjetet klime?', 'Po, te gjitha automjetet ne platforme kane sistem klimatizimi (A/C). Automjetet premium kane klime me zona te ndryshme.', 6),
('automjete', '["bluetooth","muzike","audio"]', 'A ka Bluetooth ne automjete?', 'Shumica e automjeteve kane Bluetooth per lidhje me telefonin tuaj. Automjetet me te reja kane edhe Apple CarPlay dhe Android Auto.', 5),
('automjete', '["4x4","awd","4wd","terren"]', 'A keni automjete 4x4?', 'Po, kemi SUV dhe automjete me traction 4x4 si Jeep Wrangler, Toyota Land Cruiser, dhe VW Touareg. Ideale per terren te veshtire dhe dimer.', 7),
('automjete', '["sport","sportiv","fast","shpejt"]', 'A keni automjete sportive?', 'Po, disa kompani ofrojne automjete sportive si BMW M-Series, Mercedes AMG, Porsche, dhe Audi RS. Cmimet jane ne kategorine luksoze.', 6),
('automjete', '["kabriolet","convertible","cabrio"]', 'A keni kabriolete?', 'Disa kompani ofrojne kabriolete gjate sezonit veror. Kontrolloni disponueshmerine ne faqen e automjeteve me filtrin perkates.', 5),
('automjete', '["kontroll","mirembajtje","maintenance"]', 'A jane te kontrolluara automjetet?', 'Po, te gjitha automjetet duhet te kalojne kontrollin teknik te detyrueshem. Kompanite jane te detyruara te mbajne automjetet ne gjendje te mire teknike.', 8),
('automjete', '["dyer","door"]', 'Sa dyer ka automjeti?', 'Shumica e automjeteve kane 4 dyer + bagazh. Disa modele ekonomike mund te kene 2 dyer. Numri i dyerve tregohet ne detajet e secilit automjet.', 5),
('automjete', '["ngjyre","color"]', 'A mund te zgjedh ngjyren e automjetit?', 'Ngjyra varet nga disponueshmeria. Ne faqen e secilit automjet mund te shihni ngjyren aktuale. Nese deshironi nje ngjyre specifike, kontaktoni kompanine.', 4),
('automjete', '["targa","plate","rregjistrim"]', 'A mund te udhetoj jashte shtetit me automjetin?', 'Udhetimi jashte shtetit duhet te lejohet nga kompania. Zakonisht lejohet udhetimi ne vendet e rajonit (Kosove, Shqiperi, Maqedoni) me tarife shtese 5-15 EUR/dite. Per vende te tjera, nevojitet miratim i vecante.', 8),
('automjete', '["pelqej","favorit","save"]', 'A mund ti ruaj automjetet e preferuara?', 'Aktualisht mund te shihni te gjitha automjetet e disponueshme ne faqen e automjeteve. Mund te perdorni filtrat per te gjetur automjetet qe ju pelqejne.', 4),

-- CMIME (Pricing) - 100+ responses
('cmime', '["cmim","pris","price","kosto","cost"]', 'Sa kushton qiraja e automjetit?', 'Cmimet fillojne nga 15 EUR/dite per automjete ekonomike deri ne 100+ EUR/dite per automjete luksoze. Cmimi varet nga kategoria, modeli, sezoni, dhe kohezgjatja e qiranes.', 10),
('cmime', '["zbritje","discount","oferte","offer"]', 'A ka zbritje per qira afatgjate?', 'Po, shumica e kompanive ofrojne zbritje per qira me te gjata: 10-15% per 7+ dite, 15-25% per 15+ dite, dhe 20-30% per 30+ dite. Cmimet e zbritura tregohen automatikisht.', 9),
('cmime', '["javore","weekly","jave"]', 'Sa eshte cmimi javor?', 'Cmimi javor zakonisht eshte me i ulet se 7x cmimi ditor. Per shembull, nese cmimi ditor eshte 30 EUR, cmimi javor mund te jete 180-190 EUR (zbritje 10-15%).', 8),
('cmime', '["mujore","monthly","muaj"]', 'Sa eshte cmimi mujor?', 'Per qira mujore cmimet jane dukshem me te uleta. Per shembull, nje automjet ekonomik mund te kushtoje 300-400 EUR/muaj, ndersa nje sedan 500-700 EUR/muaj.', 8),
('cmime', '["perfshire","include","perfshihet"]', 'Cfare perfshihet ne cmim?', 'Ne cmimin baze perfshihet: automjeti, sigurimi baze (TPL), taksa, dhe asistence rrugore 24/7. Nuk perfshihen: karburanti, sigurim i plote, aksesore shtese, dhe gjoba trafiku.', 10),
('cmime', '["shtese","extra","tarife"]', 'A ka tarifa shtese?', 'Tarifat shtese mund te perfshijne: shofer shtese (5-10 EUR/dite), sigurim i plote (8-15 EUR/dite), GPS (5-8 EUR/dite), ulese femijesh (3-5 EUR/dite), dhe kthim ne vend tjeter.', 8),
('cmime', '["shofer","driver","shtese"]', 'Sa kushton shtimi i nje shoferi shtese?', 'Shtimi i nje shoferi te dyte zakonisht kushton 5-10 EUR/dite. Shoferi shtese duhet te plotesoje te njejtat kushte (mosha, patenta) si shoferi kryesor.', 7),
('cmime', '["sezon","vere","dimer","season"]', 'A ndryshojne cmimet sipas sezonit?', 'Po, cmimet mund te ndryshojne sipas sezonit. Periudha e pikes (qershor-shtator dhe pushimet e fundvitit) zakonisht ka cmime 15-30% me te larta se sezoni i ulet.', 7),
('cmime', '["fature","invoice","fiskale"]', 'A leshohet fature?', 'Po, per cdo rezervim leshohet fature fiskale. Mund ta shkarkoni faturen nga paneli juaj ose ta kerkoni nga kompania ne momentin e kthimit.', 7),
('cmime', '["karte","card","cash","para"]', 'Si mund te paguaj?', 'Metodat e pageses: karte debiti/krediti (Visa, Mastercard), transferte bankare, dhe para ne dore ne disa kompani. Pagesa online eshte ne dispozicion per disa kompani.', 9),
('cmime', '["valute","eur","euro","currency"]', 'Ne cfare valute jane cmimet?', 'Te gjitha cmimet jane ne Euro (EUR). Disa kompani mund te pranojne edhe monedha lokale (LEK per Shqiperi, MKD per Maqedoni).', 6),
('cmime', '["tatim","tax","tvsh","vat"]', 'A perfshihet TVSH ne cmim?', 'Po, te gjitha cmimet e afishuara perfshijne TVSH-ne. Nuk ka tarifa te fshehura.', 7),
('cmime', '["parapagim","prepay","advance"]', 'A kerkohet parapagim?', 'Disa kompani kerkojne parapagim prej 20-30% per te siguruar rezervimin. Pjesa tjeter paguhet ne momentin e marrjes se automjetit.', 7),
('cmime', '["rimbursim","refund","kthim parash"]', 'A mund te marr rimbursim nese anuloj?', 'Po, nese anuloni me shume se 48 ore para dates se marrjes, merrni rimbursim te plote. Per anulime brenda 48 oreve, rimbursimi varet nga politika e kompanise.', 8),
('cmime', '["plan","abonim","subscription"]', 'Cilat jane planet e abonimit per kompani?', 'Ofrojme 3 plane: Baze (29.99 EUR/muaj - deri ne 10 automjete), Profesional (59.99 EUR/muaj - deri ne 50 automjete), dhe Premium (99.99 EUR/muaj - pa limit). Te gjitha planet kane zbritje per pagese vjetore.', 9),
('cmime', '["baze","basic","fillim"]', 'Cfare perfshin plani Baze?', 'Plani Baze (29.99 EUR/muaj) perfshin: deri ne 10 automjete, 50 rezervime/muaj, paneli baze i kontrollit, dhe suport me email.', 7),
('cmime', '["profesional","pro","business"]', 'Cfare perfshin plani Profesional?', 'Plani Profesional (59.99 EUR/muaj) perfshin: deri ne 50 automjete, 200 rezervime/muaj, paneli i avancuar, statistika te detajuara, suport prioritar, dhe kalendar i integruar.', 7),
('cmime', '["premium","enterprise","top"]', 'Cfare perfshin plani Premium?', 'Plani Premium (99.99 EUR/muaj) perfshin: automjete pa limit, rezervime pa limit, paneli premium, statistika te plota, suport 24/7, kalendar i integruar, API akses, dhe branding i personalizuar.', 7),
('cmime', '["vjetor","annual","yearly"]', 'A ka zbritje per pagese vjetore?', 'Po, pagesa vjetore ofron zbritje te konsiderueshme: Baze 299.99 EUR/vit (kurseni ~17%), Profesional 599.99 EUR/vit (kurseni ~17%), Premium 999.99 EUR/vit (kurseni ~17%).', 7),
('cmime', '["falas","free","pa pagese"]', 'A ka prove falas?', 'Aktualisht nuk ofrojme prove falas, por planet tona jane te dizenjuara per te qene te pershtatshme per biznese te te gjitha madhesive. Kontaktoni ekipin tone per nje demonstrim.', 5),
('cmime', '["krahasim","compare","dallim"]', 'Si dallohen planet e abonimit?', 'Dallimi kryesor eshte ne numrin e automjeteve, rezervimet mujore, dhe funksionalitetet. Plani Baze eshte per biznese te vogla, Profesional per biznese ne rritje, dhe Premium per kompani te medha.', 7);
